<?php
namespace Zclone\services;
final class CombatService { private array $stats=['small_cargo'=>[5,10,4000],'large_cargo'=>[5,25,12000],'light_fighter'=>[50,10,400],'heavy_fighter'=>[150,25,1000],'cruiser'=>[400,50,2700],'battleship'=>[1000,200,6000],'colony_ship'=>[50,100,30000],'recycler'=>[1,10,16000],'espionage_probe'=>[0,0,100]]; public function simulate(array $attacker,array $defender,array $techA=[],array $techD=[]): array { $log=[]; for($round=1;$round<=6;$round++){ [$ap,$ah]=$this->power($attacker,$techA); [$dp,$dh]=$this->power($defender,$techD); $log[]=['round'=>$round,'attacker_power'=>$ap,'defender_power'=>$dp,'attacker_hull'=>$ah,'defender_hull'=>$dh]; if ($ap>$dh*.8) $defender=$this->losses($defender,.45); if ($dp>$ah*.8) $attacker=$this->losses($attacker,.45); if (array_sum($attacker)===0 || array_sum($defender)===0) break; } $winner=array_sum($attacker)<=>array_sum($defender); return ['winner'=>$winner>0?'attacker':($winner<0?'defender':'draw'),'attacker_remaining'=>$attacker,'defender_remaining'=>$defender,'debris'=>['metal'=>random_int(100,5000),'crystal'=>random_int(50,2500)],'rounds'=>$log]; } private function power(array $fleet,array $tech): array { $p=$h=0; foreach($fleet as $ship=>$n){$s=$this->stats[$ship]??[10,10,100];$p+=$n*$s[0]*(1+.1*($tech['weapons']??0));$h+=$n*($s[1]+$s[2])*(1+.1*($tech['armor']??0));} return [$p,$h]; } private function losses(array $fleet,float $ratio): array { foreach($fleet as $k=>$v)$fleet[$k]=max(0,(int)floor($v*(1-$ratio*mt_rand(70,130)/100))); return $fleet; } }
